 1	import * as React from 'react';
 2	import { Tooltip } from '@patternfly/react-core';
 3	import { NODE_HEIGHT } from './const';
 4	import { getWhenExpressionDiamondState } from './utils';
 5	
 6	import './WhenExpressionDecorator.scss';
 7	import { ComputedStatus } from '../../types';
 8	
 9	type WhenExpressionDecoratorProps = {
10	  width: number;
11	  height: number;
12	  leftOffset?: number;
13	  stroke?: string;
14	  status: ComputedStatus;
15	  appendLine?: boolean;
16	  enableTooltip?: boolean;
17	  isFinallyTask: boolean;
18	  isPipelineRun: boolean;
19	};
20	
21	const WhenExpressionDecorator: React.FC<WhenExpressionDecoratorProps> = ({
22	  width,
23	  height,
24	  enableTooltip,
25	  appendLine = false,
26	  status,
27	  leftOffset = 2,
28	  isFinallyTask,
29	  isPipelineRun,
30	}) => {
31	  const nodeRef = React.useRef();
32	  const rotation = 45; // 45deg
33	  const { tooltipContent, diamondColor } = getWhenExpressionDiamondState(
34	    status,
35	    isPipelineRun,
36	    isFinallyTask,
37	  );
38	  const diamondHeight =
39	    Math.round(width * Math.sin(rotation)) +
40	    Math.round(height * Math.cos(rotation));
41	  const diamondNode = (
42	    <g
43	      transform={`translate(-${width * leftOffset}, ${
44	        NODE_HEIGHT / 2 - diamondHeight / 2
45	      })`}
46	      ref={nodeRef}
47	    >
48	      <rect
49	        data-test="diamond-decorator"
50	        className="opp-when-expression-decorator-diamond"
51	        width={width}
52	        height={height}
53	        fill={diamondColor}
54	        stroke={
55	          isPipelineRun
56	            ? diamondColor
57	            : 'var(--pf-t--global--border--color--100)'
58	        }
59	      />
60	      {appendLine && (
61	        <line
62	          x1={diamondHeight / 2}
63	          y1={diamondHeight / 2}
64	          x2={width * leftOffset}
65	          y2={diamondHeight / 2}
66	          stroke="var(--pf-t--global--border--color--100)"
67	          data-test="diamond-decorator-line"
68	        />
69	      )}
70	    </g>
71	  );
72	
73	  return enableTooltip ? (
74	    <Tooltip
75	      triggerRef={nodeRef}
76	      position="bottom"
77	      enableFlip={false}
78	      content={<div data-test="when-expression-tooltip">{tooltipContent}</div>}
79	    >
80	      {diamondNode}
81	    </Tooltip>
82	  ) : (
83	    diamondNode
84	  );
85	};
86	
87	export default WhenExpressionDecorator;

